using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// [BREAKING CHANGE 1] ValidateScopes is now enabled in Development.
// A singleton resolving a scoped IUserService throws InvalidOperationException.
// Fix: register CacheService as scoped so lifetimes are compatible.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// [BREAKING CHANGE 2] HttpClientFactory now creates SocketsHttpHandler by default.
// Casting to HttpClientHandler throws InvalidCastException.
// Fix: use ConfigurePrimaryHttpMessageHandler with an explicit handler.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });
// [BREAKING CHANGE 3] ForwardedHeadersMiddleware ignores X-Forwarded-* from
// proxies not listed in KnownProxies/KnownNetworks. Add your proxy address.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1")); // TODO: set your real proxy IP
});
// [BREAKING CHANGE 4] HttpClientFactory now redacts all header values in Trace logs.
// Allowlist the non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id" &&
        h != "X-Correlation-Id" &&
        h != "Cache-Control" &&
        h != "Accept"));
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

